INSERT INTO public.photos VALUES (24335, 'P.â”¬â•‘ de la Constituciâ”œâ”‚n 1983', 'Manifestaciâ”œâ”‚n contra la polâ”œÂ¡tica econâ”œâ”‚mica del Gobierno en una imagen capturada en el paseo de la Constituciâ”œâ”‚n, a la altura de las calles de Isaac Peral y de San Ignacio de Loyola, centrada en el cortejo de la primera Izquierda Unida de Aragâ”œâ”‚n, marca electoral del Movimiento Comunista de Aragâ”œâ”‚n (MCA) para las elecciones municipales de 1983. En el centro, Ricardo Berdiâ”œÂ®, presidente de la Asociaciâ”œâ”‚n de Vecinos de San Josâ”œÂ® y cabeza de lista al Ayuntamiento. Ademâ”œÃ­s: Ramâ”œâ”‚n Gâ”œâ”‚rriz Espâ”œÂ®s, sindicalista de Comisiones Obreras; la militante feminista Zoya Gâ”œâ”‚rriz; el filâ”œâ”‚sofo Josâ”œÂ® Luis Rodrâ”œÂ¡guez Garcâ”œÂ¡a; y Merche Gallizo (ex-MCA). Tras los magros resultados electorales obtenidos, en 1987 se sumarâ”œÂ¡an al nuevo proyecto de convergencia polâ”œÂ¡tica impulsado por colectivos y partidos comunistas y radicales de la izquierda aragonesa: Convergencia Alternativa de Aragâ”œâ”‚n-Izquierda Unida, actual Izquierda Unida de Aragâ”œâ”‚n.', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.64478300, -0.87744700, '0101000020E61000005F251FBB0B14ECBF2502D53F88D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48631755536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48631755536.webp', 'https://www.flickr.com/photos/zaragozaantigua/48631755536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24537, 'Calle de Miguel Servet c.1945', 'Detalle de la entrada de la boterâ”œÂ¡a de Ramâ”œâ”‚n Martâ”œÂ¡n, que posa junto a su hijo, en la calle de Miguel Servet nâ”¬â•‘ 5, local. Este veterano inmueble de dos alturas acogâ”œÂ¡a a los nâ”œâ•‘meros 5, 7, 9 y 11 de la calle. Pocos aâ”œâ–’os despuâ”œÂ®s serâ”œÂ¡a derribado y sustituido por el actual bloque del nâ”¬â•‘ 11.', 1945, 1945, 1945, 'Anos 40', 'CENTRO', 41.64825300, -0.87522600, '0101000020E6100000137CD3F4D901ECBF56444DF4F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50573506962.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50573506962.webp', 'https://www.flickr.com/photos/zaragozaantigua/50573506962/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25423, 'Puente de San Josâ”œÂ® c.1905', '"Puerta del Duque de la Victoria y Puente de San Josâ”œÂ® sobre el râ”œÂ¡o Huerva", dibujo en postal coloreada. Transita un coche de la lâ”œÂ¡nea tranviaria del Bajo Aragâ”œâ”‚n reciâ”œÂ®n electrificada.', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.64859100, -0.87561300, '0101000020E6100000747ADE8D0505ECBF6FBDA60705D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19573341072.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19573341072.webp', 'https://www.flickr.com/photos/zaragozaantigua/19573341072/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25424, 'Puente de San Josâ”œÂ® 1978', 'Puente de San Josâ”œÂ® capturado poco antes de las elecciones sindicales de 1978. Este puente ha sido el histâ”œâ”‚rico lugar por el que superar el cauce del Huerva, y acceder al camino del Bajo Aragâ”œâ”‚n y, por el camino de San Josâ”œÂ®, subir ademâ”œÃ­s a Torrero. Su original ubicaciâ”œâ”‚n estaba unos 300 metros aguas abajo, donde en los â”œâ•‘ltimos aâ”œâ–’os del XVI se instalâ”œâ”‚ un convento carmelita descalzo bajo la advocaciâ”œâ”‚n de San Josâ”œÂ®, que terminâ”œâ”‚ transfiriâ”œÂ®ndole la denominaciâ”œâ”‚n. La ruina de ese puente en piedra sillar llevâ”œâ”‚, con el tiempo, a esta nueva ubicaciâ”œâ”‚n, que acelerâ”œâ”‚ la apertura de la plaza de San Miguel como vâ”œÂ¡a de ingreso a la ciudad, pues hasta entonces no lo era. En la imagen, aspecto del puente cuando junto a â”œÂ®l estaba, desde 1975, el acceso al Canâ”œâ”‚dromo Zaragoza, un lucrativo lugar donde 3000 personas veâ”œÂ¡an correr perros. A su lado, el Garaje Solano. A la derecha, bajo el "Stop", las instalaciones del "Tenis", que ese mismo aâ”œâ–’o fueron cambiadas por unas nuevas en la carretera del Aeropuerto.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.64859100, -0.87561300, '0101000020E6100000747ADE8D0505ECBF6FBDA60705D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19799956374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19799956374.webp', 'https://www.flickr.com/photos/zaragozaantigua/19799956374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25433, 'Calle Miguel Servet c.1920', 'Calle de Miguel Servet en una imagen realizada desde la glorieta que daba inicio a este vial. A la izquierda y ante el puente de san Josâ”œÂ®, ingreso a los lavaderos de san Josâ”œÂ® y la fâ”œÃ­brica de pastas para sopa de Pedro Maldonado. A la derecha, ingreso al lavadero Hondo asâ”œÂ¡ llamado por estar a medio camino entre la altura de la calle y el cauce del râ”œÂ¡o. Sobre el firme, la vâ”œÂ¡a doble tranviaria de la lâ”œÂ¡nea del Bajo Aragâ”œâ”‚n y conducente a las cocheras de la empresa. Al fondo destaca la torre de la iglesia de san Miguel de los Navarros. Fuente: Foto Jesâ”œâ•‘s Cormâ”œÃ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.64859100, -0.87561300, '0101000020E6100000747ADE8D0505ECBF6FBDA60705D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24619426680.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24619426680.webp', 'https://www.flickr.com/photos/zaragozaantigua/24619426680/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25578, 'R. Z. C. Tenis 1958', 'El C. D. Iberia jugâ”œâ”‚ ese aâ”œâ–’o la fase de ascenso a la 1â”¬Â¬ divisiâ”œâ”‚n del baloncesto, y lo hizo jugando de local en la cancha del R. Z. C. Tenis. Sus rivales fueron el Espaâ”œâ–’ol de Barcelona y el Espaâ”œâ–’ol de Valencia, y consiguiâ”œâ”‚ su objetivo, convirtiâ”œÂ®ndose en el primer equipo amateur que consiguiâ”œâ”‚ llegar hasta la mâ”œÃ­xima categorâ”œÂ¡a del baloncesto espaâ”œâ–’ol. En la imagen, aspecto rebosante de pâ”œâ•‘blico de la cancha del "Tenis" en uno de los encuentros de esa fase de ascenso. Detrâ”œÃ­s del muro, los â”œÃ­rboles de la ribera del Huerva, y un poco mâ”œÃ­s allâ”œÃ­, la mole del "Gas", el complejo del Gasâ”œâ”‚metro, entre el Huerva, Miguel Servet, y el Camino de las Torres. Fuente visual: www.lacasadelbaloncesto.es/Visor.asp?id=1114&Fon=384', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64784700, -0.87712500, '0101000020E6100000C520B0726811ECBFE6E786A6ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15264768479.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15264768479.webp', 'https://www.flickr.com/photos/zaragozaantigua/15264768479/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25584, 'Puente de San Josâ”œÂ® 1860', 'Vista del puente de San Josâ”œÂ® sobre el râ”œÂ¡o Huerva, con la iglesia de San Miguel de los Navarros detrâ”œÃ­s. Fuente: Mariano Jâ”œâ•‘dez y Ortiz, 1859-1860. â”œÃ¼lbum de Andrâ”œÂ®s Martâ”œÂ¡n e Ipâ”œÃ­s. Col. Mariano Martâ”œÂ¡n Casalderrey. Libro Primeros tiempos de la fotografâ”œÂ¡a en Zaragoza.', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.64859100, -0.87561300, '0101000020E6100000747ADE8D0505ECBF6FBDA60705D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20486843881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20486843881.webp', 'https://www.flickr.com/photos/zaragozaantigua/20486843881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25587, 'Paseo de la Mina 1960', 'Vista aâ”œÂ®rea del paseo de la Mina y su entorno. Inmediatos, los edificios del arranque de Miguel Servet. A la izquierda, el gasâ”œâ”‚metro y el solar del antiguo lavadero de la seâ”œâ–’ora Benita. Sobre la lâ”œÂ¡nea arbolada del râ”œÂ¡o Huerva, las instalaciones del Tenis. Arriba a la izquierda, la harinera Samper y el colegio de Corazonistas. A la derecha, la plaza de Josâ”œÂ® Antonio y los edificios de la Exposiciâ”œâ”‚n Hispano-Francesa de 1908. En beneficio de todos, hemos volteado horizontalmente la imagen original. Fuente visual: Arxiu Nacional de Catalunya', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.64835000, -0.87654700, '0101000020E61000006C054D4BAC0CECBF492EFF21FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27561259233.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27561259233.webp', 'https://www.flickr.com/photos/zaragozaantigua/27561259233/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25590, 'Camino de las Torres 1960', 'Vista aâ”œÂ®rea sobrevolando el camino de las Torres en el tramo entre el antiguo paseo de los Plâ”œÃ­tanos, y hasta casi su desemboque en Miguel Servet, donde el colegio de la Salle Montemolâ”œÂ¡n. A la izquierda, el râ”œÂ¡o Huerva serpentea en la zona del colegio del Sagrado Corazâ”œâ”‚n del paseo de la Mina, y las antiguas harineras de Marcos Samper, y los hermanos Solsona. A ambos lados del camino de las Torres, un panorama de antiguas torres agrâ”œÂ¡colas, en el que destaca el descomunal depâ”œâ”‚sito del "Gas". En beneficio de todos, hemos volteado horizontalmente la imagen original. Fuente visual: Arxiu Nacional de Catalunya', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.64597100, -0.87840100, '0101000020E61000001EC2F869DC1BECBF0C957F2DAFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31746764455.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31746764455.webp', 'https://www.flickr.com/photos/zaragozaantigua/31746764455/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25734, 'Polâ”œÂ¡gono Miraflores 1976', 'Es abril, pero no verdea mucho la prolongaciâ”œâ”‚n de Marina Moreno, que digamos. Hay una especie dominante: los postes de madera de los tendidos elâ”œÂ®ctricos (recuerdo de cuando este era ferial en octubre), y por debajo de ellos, poco recuerdo de los campos, huertos, riegos, sendas, torres. La imagen estâ”œÃ­ capturada desde donde hoy se levanta el C.E.I.P. Miraflores, y presenta una interesante panorâ”œÃ­mica de lo que la actual avenida de Cesâ”œÃ­reo Alierta era entonces: una nada con nueve modernos carriles para trâ”œÃ­fico rodado que conducâ”œÂ¡a a la avenida de San Josâ”œÂ® desde el camino de las Torres. De izquierda a derecha, en primer lugar, los edificios de la antigua calle de la Licorera (desde 1979 calle del Escultor Francisco Burriel), todos desaparecidos. Despuâ”œÂ®s, el edificio de la avenida de San Josâ”œÂ® derribado sobre el que en 1988 se levantaron el nâ”¬â•‘ 54 y 56 de la avenida. A continuaciâ”œâ”‚n, los ya veteranos bloques de los nâ”œâ•‘meros 58 a 66 (1964), y el nâ”¬â•‘ 55 y 57 de Marina Moreno. Desde ahâ”œÂ¡, construcciones variopintas de la avenida de San Josâ”œÂ® (algunas sobreviven hoy, pendientes de acuerdos entre herederos para construir y urbanizar la zona), incluyendo la parroquia de San Agustâ”œÂ¡n, hasta la calle de Cartagena. Finalmente, y ante la ausencia de edificaciones en altura en los nâ”œâ•‘meros pares de ese tramo de la avenida (ademâ”œÃ­s, la actual calle de Illueca no existâ”œÂ¡a), visual de los nâ”œâ•‘meros 97 (derribado y reconstruido en 1985), 99 (de 1974) y 103 (de 1972). Fuente visual: AVV San Josâ”œÂ®.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.64055900, -0.87652400, '0101000020E61000006117450F7C0CECBF49145AD6FDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20249115782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20249115782.webp', 'https://www.flickr.com/photo