INSERT INTO public.photos VALUES (25762, 'Fâ”œÃ­brica de Pastas 1927', 'Membrete de factura de la Fâ”œÃ­brica de Pastas para Sopa de Pedro Maldonado (antigua Maldonado Hermanos), en la calle Miguel Servet 6. En el dibujo se ve la ubicaciâ”œâ”‚n de la factorâ”œÂ¡a, en la actual esquina con la calle de Coâ”œÂ¡mbra. En primer plano, el puente de San Josâ”œÂ® sobre el râ”œÂ¡o Huerva. Fuente: www.todocoleccion.net', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64851700, -0.87570000, '0101000020E61000002F6EA301BC05ECBF34F3E49A02D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30827619735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30827619735.webp', 'https://www.flickr.com/photos/zaragozaantigua/30827619735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25794, 'Prolongaciâ”œâ”‚n de Marina Moreno 1976', 'Imagen capturada en el denominado "Polâ”œÂ¡gono 12" del barrio de San Josâ”œÂ® donde la prolongaciâ”œâ”‚n del paseo de Marina Moreno se nos muestra tras su cruce con el camino de las Torres, y centrada en los edificios del â”œâ•‘ltimo tramo de la calle de Manuel Lorenzo Pardo, en el que destacan los elevados inmuebles recayentes, a la izquierda, al camino de las Torres. En el centro de la escena se abre el entonces desemboque de la calle de la Reina Fabiola. En primer tâ”œÂ®rmino, calzada de la prolongaciâ”œâ”‚n del paseo de Marina Moreno y solares convertidos en presas codiciadas por la especulaciâ”œâ”‚n inmobiliaria de la â”œÂ®poca que, a pesar de lo dispuesto en la legislaciâ”œâ”‚n de la zona, consiguiâ”œâ”‚ que se practicara tambiâ”œÂ®n aquâ”œÂ¡ el "urbanismo a la carta" para elevar de forma notable la densidad residencial que el PGOU establecâ”œÂ¡a como mâ”œÃ­ximo en 400 habitantes por metro cuadrado, para llegar a los 1263. Esta urbanizaciâ”œâ”‚n se hizo sin previsiâ”œâ”‚n de suelo para dotaciones de servicios y con el mâ”œÂ¡nimo de zonas verdes (que desde el Colegio de Arquitectos se calificaban con cierta retranca de "grandes macetas"), elevando tambiâ”œÂ®n, como derivada lâ”œâ”‚gica, la congestiâ”œâ”‚n del trâ”œÃ­fico rodado privado. Los solares de la imagen comenzarâ”œÂ¡an a edificarse poco despuâ”œÂ®s de la toma de esta fotografâ”œÂ¡a, completâ”œÃ­ndose a finales de los aâ”œâ–’os ochenta. Todas las viviendas de esta zona eran, por supuesto, de "libre acceso", o "libres".', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.64431300, -0.87615800, '0101000020E6100000DE1E84807C09ECBF9EB12FD978D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54693514422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54693514422.webp', 'https://www.flickr.com/photos/zaragozaantigua/54693514422/', 'Zaragoza Antigua (Flickr)', '