INSERT INTO public.photos VALUES (25861, 'Multicines Buâ”œâ–’uel 2007', 'Foto: Marâ”œÂ¡a Torres-Solanot. Aspecto de la entrada de los Multicines Buâ”œâ–’uel en la calle de Francisco de Vitoria 30 de Zaragoza, dos dâ”œÂ¡as antes de su cierre el viernes 6 de julio de 2007. Estas cuatro salas de proyecciâ”œâ”‚n fueron inauguradas en abril de 1977, a iniciativa del Partido Comunista de Espaâ”œâ–’a, aunque desde 1980 pertenecâ”œÂ¡an a la empresa Lauren Films. Fuente visual: Colecciâ”œâ”‚n Particular.', 2007, 2007, 2007, 'Siglo XXI', 'CENTRO', 41.64483800, -0.87888600, '0101000020E610000033315D88D51FECBFE99B340D8AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21569064523.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21569064523.webp', 'https://www.flickr.com/photos/zaragozaantigua/21569064523/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26023, 'P.â”¬â•‘ de Marina Moreno 1974', 'Aâ”œÂ®rea visual capturada sobre la prolongaciâ”œâ”‚n del paseo de Marina Moreno. Destaca el estado constructivo en gestaciâ”œâ”‚n de la manzana correspondiente a los nâ”œâ•‘meros 16-24 del paseo. En primer tâ”œÂ®rmino, el gran solar de la antigua fâ”œÃ­brica de harinas de Solsona y de la torre de Labastida, delimitado entre el colegio del Sagrado Corazâ”œâ”‚n, el râ”œÂ¡o Huerva y las instalaciones de la fâ”œÃ­brica de gas (hacia la derecha, fuera de plano). Fuente visual: Josâ”œÂ® Jaria Serrano, en AMZ.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64550800, -0.87790700, '0101000020E61000003CBEBD6BD017ECBF37A79201A0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28210579089.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28210579089.webp', 'https://www.flickr.com/photos/zaragozaantigua/28210579089/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20868, 'Baâ”œâ–’os judâ”œÂ¡os s. XIII', 'Ayuntamiento de Zaragoza, c. 2000. La parte conservada de los baâ”œâ–’os judâ”œÂ¡os de Zaragoza del siglo XIII se encuentra en la calle Coso 126-132. "Su emplazamiento quedaba frente a la Juderâ”œÂ¡a y especialmente frente a la fortaleza conocida por Castillo de los Judâ”œÂ¡os, que estaba sobre el solar que actualmente ocupa el Seminario de San Carlos. Este Castillo de los Judâ”œÂ¡os servâ”œÂ¡a tambiâ”œÂ®n de câ”œÃ­rcel, sinagoga mayor, hospital y carnicerâ”œÂ¡a. Lo conservado es â”œâ•‘nicamente una sala de planta ligeramente rectangular, organizada a modo de claustro, con cuatro tramos en las galerâ”œÂ¡as cortas y cinco en las largas, abovedados con crucerâ”œÂ¡a sencilla, con diez columnas para separarlos del espacio central tambiâ”œÂ®n rectangular y cubierto por bâ”œâ”‚veda esquifada." Fuente: www.zaragoza.es/ciudad/postales/medieval.htm', 1250, 1200, 1299, 'Siglo XIX', 'CENTRO', 41.65103300, -0.87554900, '0101000020E6100000C57421567F04ECBFF2CEA10C55D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14804010000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14804010000.webp', 'https://www.flickr.com/photos/zaragozaantigua/14804010000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25540, 'Desembocadura râ”œÂ¡o Gâ”œÃ­llego 2012', 'Imagen aâ”œÂ®rea de la desembocadura del râ”œÂ¡o Gâ”œÃ­llego en el Ebro a la altura de la ciudad de Zaragoza, en 2012. Fuente: www.zaragoza.es', 2012, 2012, 2012, 'Siglo XXI', 'LAS FUENTES', 41.65100900, -0.84822500, '0101000020E610000086C954C1A824EBBF6A334E4354D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19909177002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19909177002.webp', 'https://www.flickr.com/photos/zaragozaantigua/19909177002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20885, 'Plaza de la Sinagoga 1250', 'Dibujo incorporado a uno de los libelos que divulgaron a finales del siglo XIX y principios del XX el fantâ”œÃ­stico y difamatorio rapto y asesinato del infantico Dominguito de Val por los judâ”œÂ¡os de la Zaragoza de mediados del siglo XIII. La escena recogerâ”œÂ¡a el imaginario momento en que uno de los judâ”œÂ¡os recoge en una copa la sangre del infantico para beberla luego durante la Pascua de Sangre. Segâ”œâ•‘n esta retorcida creencia, este caso serâ”œÂ¡a un ejemplo de los rituales secuestros de niâ”œâ–’os cristianos realizados para luego asesinarlos y beber su sangre y celebrar de esta enfermiza forma la liberaciâ”œâ”‚n del pueblo judâ”œÂ¡o de la esclavitud a la que fue sometido durante su estancia en el antiguo Egipto. A la derecha del dibujo, representaciâ”œâ”‚n del ficticio Mossâ”œÂ® Albayucet, rabino que, ademâ”œÃ­s de protagonizar el rapto del infante, habrâ”œÂ¡a sido quien le clavâ”œâ”‚ a un muro interior de la Sinagoga mayor, inmediata al callizo del Talmud, como delata el martillo que aâ”œâ•‘n lleva en su mano derecha. Mientras tanto y a la izquierda, otros judâ”œÂ¡os parecen regodearse con el hecho, y uno de ellos porta una lanza que luego clavarâ”œÂ¡a en el costado del niâ”œâ–’o. Esta rocambolesca y truculenta historieta, bien poco amable, era la zaragozana adaptaciâ”œâ”‚n de una leyenda inglesa inventada el siglo anterior, y contenâ”œÂ¡a una ominosa ramificaciâ”œâ”‚n orientada a la incitaciâ”œâ”‚n fanâ”œÃ­tica al odio racial y religioso de las minorâ”œÂ¡as no cristianas residentes en la ciudad desde siglos antes. Fuente visual: padre-hernanvergara.com', 1250, 1250, 1250, 'Siglo XIX', 'CENTRO', 41.65135200, -0.87595400, '0101000020E6100000BF9CD9AED007ECBF941799805FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40033118203.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40033118203.webp', 'https://www.flickr.com/photos/zaragozaantigua/40033118203/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20933, 'Colegio de los Jesuitas 1585', 'La imagen reproduce el dibujo con la planta para el nuevo "Colegio de Zaragoza" de la Compaâ”œâ–’â”œÂ¡a de Jesâ”œâ•‘s, proyectado en el terreno adquirido en 1555 por los jesuitas donde estuviera la antigua Sinagoga mayor de la ciudad, ademâ”œÃ­s del "Castillo", el "Hospital", y la "Carnicerâ”œÂ¡a" de los judâ”œÂ¡os, una compacta manzana entre la plaza de la Sinagoga (el "Septentriâ”œâ”‚n" del plano), la calle y puerta de la Carnicerâ”œÂ¡a de los Judâ”œÂ¡os ("Poniente"), el Coso ("Medio Dia"), y la calle de la Cunequia ("Oriente"). Al poco de la compra de este terreno, a finales de 1555, aquâ”œÂ¡ fue erigida una iglesia provisional bajo la advocaciâ”œâ”‚n de la Inmaculada Concepciâ”œâ”‚n, y aunque este proyectado Colegio no se ejecutâ”œâ”‚ en su literalidad, serâ”œÃ­ la gâ”œÂ®nesis del enorme complejo jesuâ”œÂ¡tico que a comienzos del siglo XVII fue construido en la capital del reino de Aragâ”œâ”‚n. La incidencia de este Colegio de nueva planta en el nomenclâ”œÃ­tor de Zaragoza fue tambiâ”œÂ®n importante: la antigua plaza de la Sinagoga se convirtiâ”œâ”‚ en la calle del Horno de la Compaâ”œâ–’â”œÂ¡a, y la calle de la Cunequia, en la de la Compaâ”œâ–’â”œÂ¡a. Fuente visual: Biblioteca Nacional de Parâ”œÂ¡s.', 1585, 1585, 1585, 'Siglo XIX', 'CENTRO', 41.65118900, -0.87527000, '0101000020E6100000FC6F253B3602ECBFEA4141295AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25175912406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25175912406.webp', 'https://www.flickr.com/photos/zaragozaantigua/25175912406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20954, 'Seminario 1808', 'Ruinas del Seminario. Serie Ruinas de Zaragoza, de Juan Gâ”œÃ­lvez (dibujo) y Fernando Brambila (grabado), Câ”œÃ­diz, 1812. Vista del Coso Bajo de Zaragoza, desde la actual calle de Romea, mirando hacia Las Piedras del Coso. A nuestra derecha, las ruinas del conjunto de construcciones del Seminario, incluyendo la actual calle de San Jorge, entre el edificio aâ”œâ•‘n hoy en pie, con la torreta, y el que vemos en primer plano. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65130400, -0.87524300, '0101000020E610000096B1A19BFD01ECBF83E0F1ED5DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15248519736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15248519736.webp', 'https://www.flickr.com/photos/zaragozaantigua/15248519736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20986, 'San Pedro Nolasco 1855', '"Patio de una casa en la plaza de San Pedro Nolasco de Zaragoza". Dibujo de Valentâ”œÂ¡n Carderera y Solano, realizado en 1855, con una vista del renancentista patio de una casa seâ”œâ–’orial localizada en la plaza de San Pedro Nolasco, donde la iglesia parroquial de San Lorenzo Mâ”œÃ­rtir, y la iglesia del colegio de San Pedro Nolasco, definen un pequeâ”œâ–’o espacio entre la calle Alta de San Pedro, y la de la Enseâ”œâ–’anza. En el momento de realizaciâ”œâ”‚n del dibujo, se identifica a su propietario como "Lazatornil", posiblemente arrendatario del cercano molino de aceite del antiguo colegio de San Vicente. Cuando, al poco, se remodele el espacio de la plaza, con el derribo de la iglesia de San Lorenzo incluido (1866), este palacio renacentista serâ”œÃ­ derribado. Fuente visual: ceres.mcu.es/', 1855, 1855, 1855, 'Siglo XIX', 'CENTRO', 41.65258700, -0.87679100, '0101000020E610000019ABCDFFAB0EECBFBA6587F887D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24383138774.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24383138774.webp', 'https://www.flickr.com/photos/zaragozaantigua/24383138774/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21054, 'Palacio de los Morlanes 1872', 'A.M.Z. Sign. 0848. Ronda zaragozana. [1872]. El dibujo reproduce un cuadro de Nicolâ”œÃ­s Ruiz de Valdivia, en el que una rondalla jotera efectâ”œâ•‘a un ritual amoroso en la madrugada de san Juan, entregando un ramo de flores en la ventana de la casa palacio de los Morlanes, sita en la confluencia de la plaza de san Carlos con la calle de San Jorge.', 1872, 1872, 1872, 'Siglo XIX', 'CENTRO', 41.65167200, -0.87569700, '0101000020E6100000EA9106B7B505ECBF05DCF3FC69D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14856448464.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14856448464.webp', 'https://www.flickr.com/photos/zaragozaantigua/14856448464/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21096, 'Coso Bajo c.1880', 'El Coso bajo desde las "Piedras del Coso". A la izquierda, esquinera con la calle Santo Dominguito de Val, la gran estructura de los Graneros de la ciudad, reconvertidos precariamente en 1899 en dos escuelas municipales, ademâ”œÃ­s de acoger una escuela-asilo de la organizaciâ”œâ”‚n catâ”œâ”‚lica de La Caridad y un espacio reservado como almacâ”œÂ®n municipal. Tras ellos, el Seminario de San Carlos Borromeo tras ser retranqueado. El Coso bajo, sin los raâ”œÂ¡les de la lâ”œÂ¡nea de Circunvalaciâ”œâ”‚n. Fuente visual: Estudio Coyne, en DARA-AHPZ.', 1880, 1880, 1880, 'Siglo XIX', 'CENTRO', 41.65091200, -0.87582800, '0101000020E61000008E791D71C806ECBF77499C1551D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14777094938.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14777094938.webp', 'https://www.flickr.com/photos/zaragozaantigua/14777094938/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21264, 'Seminario de San Carlos 1907', 'Postal. "Colecciâ”œâ”‚n Patria y Fe nâ”œâ•‘m. 20, Zaragoza 1908 - Centenario de los Sitios", 1907. "Destruido por la explosiâ”œâ”‚n del depâ”œâ”‚sito de pâ”œâ”‚lvora, ocurrida el 27 de junio y que dejâ”œâ”‚ sin municiones a la ciudad. Contiguo a este edificio se levantaba el Colegio de la Compaâ”œâ–’â”œÂ¡a, destruido tambiâ”œÂ®n." Las destrucciones fueron parciales, como atestigua la fotografâ”œÂ¡a de un siglo despuâ”œÂ®s, y el estado actual del edificio. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.65127000, -0.87502200, '0101000020E6100000F4F928232E00ECBFD66EBBD05CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20770056885.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20770056885.webp', 'https://www.flickr.com/photos/zaragozaantigua/20770056885/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21446, 'Calle de la Yedra c.1911', 'Imagen capturada en el segundo y â”œâ•‘ltimo tramo de la calle de la Yedra, desde la calle de los Graneros y con el fondo del ancho desemboque en la calle de Santo Dominguito de Val, donde destaca la portada de la antigua casa de los marqueses de Torrecilla. En primer tâ”œÂ®rmino y a la izquierda, el inmueble del nâ”¬â•‘ 11 de la calle de la Yedra. A la derecha, los edificios de los nâ”œâ•‘meros 8 y 10. La notable presencia de obreros se debe a la celebraciâ”œâ”‚n de una reuniâ”œâ”‚n en la sede de la Federaciâ”œâ”‚n local de Sociedades Obreras ubicada en la denominada "casa de Santo Dominguito", antigua casa de los Salavert, Sora y Torrecilla, con ingreso desde la transversal calle de Santo Dominguito.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.65163100, -0.87650200, '0101000020E61000006D1D1CEC4D0CECBFA70705A568D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49951686093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49951686093.webp', 'https://www.flickr.com/photos/zaragozaantigua/49951686093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21537, 'Calle San Jorge 1929', 'Dibujo de Ambrosio Ruste representando el tramo de la calle de San Jorge entre la plaza de San Pedro Nolasco y la actual calle de San Vicente de Paâ”œâ•‘l. Anteriormente, esta ubicaciâ”œâ”‚n era llamada calle de la Enseâ”œâ–’anza, por albergar en ella el Convento de las Madres de la Enseâ”œâ–’anza, religiosas de la Compaâ”œâ–’â”œÂ¡a de Jesâ”œâ•‘s. Su templo anexo fue derribado en 1929. Al fondo, la torre de la iglesia de la Concepciâ”œâ”‚n, en el Seminario de San Carlos. Fuente: â”¬Ã­Aquâ”œÂ¡... Zaragoza!, Josâ”œÂ® Blasco Ijazo, 1954.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65211200, -0.87607300, '0101000020E610000051137D3ECA08ECBF22AAF06778D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19834751165.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19834751165.webp', 'https://www.flickr.com/photos/zaragozaantigua/19834751165/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21565, 'Calle San Jorge 1929', 'Imagen de una calle San Jorge insâ”œâ”‚litamente amplia, como consecuencia del reciente derribo del antiguo colegio de "La Enseâ”œâ–’anza" de la Compaâ”œâ–’â”œÂ¡a de Marâ”œÂ¡a, que con su traslado a nuevas dependencias de la calle Bilbao posibilitâ”œâ”‚ reordenar el urbanismo de la zona. A la izquierda, el edificio esquinero con la calle de la Zarza seâ”œâ–’ala la tradicional anchura "de toda la vida" de la calle de la Compaâ”œâ–’â”œÂ¡a (luego San Jorge). Frente a â”œÂ®l, la mole del Real Seminario de San Carlos Borromeo de los PP. Jesuitas, la plaza de San Carlos, y una panorâ”œÃ­mica como nunca se habâ”œÂ¡a dado del renacentista palacio de los Morlanes. Unos aâ”œâ–’os despuâ”œÂ®s, el edificio entre la calle de la Zarza y de los Estudios tambiâ”œÂ®n serâ”œÃ­ retranqueado, y sobre el solar de primer plano se construirâ”œÂ¡an nuevos edificios de vivienda, configurando este tramo de la calle tal y como ahora es. Fuente visual: Juan Mora Insa, DARA-AHPZ.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65188100, -0.87565400, '0101000020E6100000199293895B05ECBF20F12BD670D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23047894346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23047894346.webp', 'https://www.flickr.com/photos/zaragozaantigua/23047894346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21674, 'Palacio Sora 1930', 'AHPZ-Archivo MORA. 1930. Imagen del Palacio Salabert, de Torrecilla, o Sora, sito en la calle del Limâ”œâ”‚n (luego Sto. Dominguito de Val) hasta su derribo en abril de 1936. Se le considera original sede del Talmud de la Juderâ”œÂ¡a Vieja, por su proximidad a la Sinagoga Principal (actual Seminario de S. Carlos Borromeo). Tras la expulsiâ”œâ”‚n de judâ”œÂ¡os y judâ”œÂ¡as decretada en 1492 por los Reyes Catâ”œâ”‚licos, la juderâ”œÂ¡a fue "recalificada", y esta casa vendida al notario Domingo Salabert, a precio bajo de cristiano viejo. El Palacio fue levantado en el siglo XVI, en formas y estilo renacentista, pero a la zaragozana (en ladrillo). Reformado en el XVII, se le aâ”œâ–’adiâ”œâ”‚ una portada en piedra de factura barroco-manierista. Desde 1869 esta zona quedâ”œâ”‚ incluida en un municipal plan de apertura de una nueva calle desde el Coso hasta el Paseo del Ebro, proyecto totalmente terminado en junio de 1951. La calle de La Yedra, y su continuaciâ”œâ”‚n de Villalobos, por las que se podâ”œÂ¡a acceder al Palacio desde el Coso, fueron piqueteadas, como la calle del Limâ”œâ”‚n, que era su direcciâ”œâ”‚n postal. Del Palacio sobrevive un retablo barroco en el Museo de la ciudad, y la barroca portada, que desde el derribo del Palacio andaba extraviada, hasta que se apareciâ”œâ”‚ en mortal piedra en 1941, y los hermanos Borobio la incrustaron en la fachada del nuevo Convento de monjas de la calle Salduba nâ”¬â•‘ 8. Allâ”œÂ¡ continâ”œâ•‘a. En la imagen, la fachada y portada del Palacio de Sora desde la Calle del Limâ”œâ”‚n. A su derecha, y al fondo, el edificio de factura modernista que, bajo la denominaciâ”œâ”‚n postal de "Santo Dominguito Val, nâ”¬â•‘ 11", perdura en nuestros dâ”œÂ¡as. El solar del Palacio hoy estâ”œÃ­ ocupado por el nâ”¬â•‘ 8 de S. Vicente de Paâ”œâ•‘l, y por un pedazo de la calle del mismo nombre.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65152700, -0.87652900, '0101000020E6100000D3DB9F8B860CECBF02BB9A3C65D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14829858256.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14829858256.webp', 'https://www.flickr.com/photos/zaragozaantigua/14829858256/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21683, 'Palacio de Sora aâ”œâ–’os 30', 'AHPZ-Archivo Fotogrâ”œÃ­fico Josâ”œÂ® Galiay, (SF). Portada del Palacio de Sora o Salabert.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65155900, -0.87636800, '0101000020E6100000865968E7340BECBF0D350A4966D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14887569135.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14887569135.webp', 'https://www.flickr.com/photos/zaragozaantigua/14887569135/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21690, 'Plaza San Pedro Nolasco aâ”œâ–’os 30', 'Mercado al aire libre en la plaza San Pedro Nolasco, siguiendo la tradiciâ”œâ”‚n del lugar. Al fondo, calle San Jorge hacia Don Jaime. Fuente: Heraldo de Aragâ”œâ”‚n.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65270400, -0.87697500, '0101000020E6100000711B0DE02D10ECBFF4FBFECD8BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15054814501.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15054814501.webp', 'https://www.flickr.com/photos/zaragozaantigua/15054814501/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21882, 'Calle de Santo Dominguito de Val 1930', 'Imagen capturada en la calle de la Yedra y centrada en la portada principal de la casa del siglo XVI de los Salavert o Sora, que a finales del siglo XVII fueron ennoblecidos con el tâ”œÂ¡tulo de marqueses de Torrecilla. Realizado en ese siglo destaca precisamente el barroco ingreso manierista a la casa, â”œâ•‘nico resto pâ”œÂ®treo de esta singular casa que perdura, en otra ubicaciâ”œâ”‚n, tras su derribo cuando la apertura de la nueva calle de San Vicente de Paâ”œâ•‘l.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65163900, -0.87652400, '0101000020E61000006117450F7C0CECBF2AE620E868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47850389482.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47850389482.webp', 'https://www.flickr.com/photos/zaragozaantigua/47850389482/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25970, 'Fernando el Catâ”œâ”‚lico 1945', 'Desde la torre-mirador de la nueva Feria de Muestras (Regino y Josâ”œÂ® Borobio Ojeda, 1943), una vista panorâ”œÃ­mica al estado de cosas en la nueva, arbolada (y poco mâ”œÃ­s) Avenida de Fernando el Catâ”œâ”‚lico. La acera izquierda, hasta casi llegar a la Plaza de San Francisco, es un erial a la espera de edificaciones. La gente pasea por caminos de tierra, atravesando los solares por la tangente. A la derecha, la Imprenta Luis Vives, y los bloques del Grupo de Viviendas "Francisco Caballero". La nueva Plaza de San Francisco, aâ”œâ•‘n desprovista de sus caracterâ”œÂ¡sticos edificios con porches, como abierto espacio de carpas y atracciones. Al fondo, la câ”œâ•‘pula de Santiago el Mayor, el Pilar con dos torres, y la Seo. A la derecha, al fondo, el monumental gasâ”œâ”‚metro de Camino de las Torres.', 1945, 1945, 1945, 'Anos 40', 'UNIVERSIDAD', 41.63746400, -0.89863600, '0101000020E6100000A243E048A0C1ECBF4D309C6B98D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14927363991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14927363991.webp', 'https://www.flickr.com/photos/zaragozaantigua/14927363991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21955, 'Colegio del Pilar 1946', 'Dibujo del edificio del Colegio del Pilar de los Hermanos Maristas, con fachada principal a San Vicente de Paâ”œâ•‘l 11 al 17, inaugurado en 1946. A la izquierda, calle de San Jorge; a la derecha la de San Lorenzo; detrâ”œÃ­s, la plaza de San Pedro Nolasco, a donde daba su patio. El edificio, obra de Fâ”œÂ®lix Ortiz, tardâ”œâ”‚ tres aâ”œâ–’os en construirse. Su orientaciâ”œâ”‚n respondâ”œÂ¡a a la apertura de la nueva calle de San Vicente de Paâ”œâ•‘l, cuyas obras se prolongaron entre 1936 y 1951. En 1981, los Maristas participaron en la no declarada "Operaciâ”œâ”‚n conventos y colegios privados", yâ”œÂ®ndose a la periferia (calle de Rafael Alberti 5) y quedando el inmueble en propiedad municipal. Fue sede del Instituto Mixto nâ”œâ•‘mero 4 en 1986, pese a su estado de abandono, como alternativa al desplome de esta unidad educativa en la plaza del Portillo. Tras su posterior adquisiciâ”œâ”‚n y restauraciâ”œâ”‚n por la Diputaciâ”œâ”‚n General de Aragâ”œâ”‚n, ahora alberga algunas de sus dependencias. Fuente: â”¬Ã­Aquâ”œÂ¡... Zaragoza!, Josâ”œÂ® Blasco Ijazo, 1953.', 1946, 1946, 1946, 'Anos 40', 'CENTRO', 41.65244700, -0.87599900, '0101000020E6100000BE840A0E2F08ECBFC9AF1F6283D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19866047971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19866047971.webp', 'https://www.flickr.com/photos/zaragozaantigua/19866047971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21994, 'Plaza San Pedro Nolasco c.1942', 'Acuarela de Ambrosio Ruste, que muestra la iglesia del Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s (1942) en la plaza de San Pedro Nolasco. Fuente: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1942, 1942, 1942, 'Anos 40', 'CENTRO', 41.65251700, -0.87699800, '0101000020E61000007D09151C5E10ECBFC28A53AD85D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31627219583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31627219583.webp', 'https://www.flickr.com/photos/zaragozaantigua/31627219583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22023, 'Iglesia del Sagrado Corazâ”œâ”‚n 1944', 'Imagen capturada en el interior de la moderna iglesia del Sagrado Corazâ”œâ”‚n diseâ”œâ–’ada por Josâ”œÂ® y Regino Borobio Ojeda y sita en la plaza de San Pedro Nolasco sobre el solar de la antigua y homâ”œâ”‚nima iglesia que fue derribada para dar paso a un programa constructivo para la orden de los jesuitas que incluâ”œÂ¡a esta iglesia y una residencia. La escena recoge la celebraciâ”œâ”‚n de la fiesta de la "Cruzada Eucarâ”œÂ¡stica" que desde su instauraciâ”œâ”‚n durante le pontificado de Pâ”œÂ¡o X buscaba fomentar entre los escolares y desde la mâ”œÃ­s temprana edad "la frecuente y digna recepciâ”œâ”‚n de la Sagrada Comuniâ”œâ”‚n" mediante la realizaciâ”œâ”‚n de cuatro consignas "ora, comulga, sacrifâ”œÂ¡cate, sâ”œÂ® apâ”œâ”‚stol". Al fondo, testero orientado hacia el sur con el altar que culminaba la visual de la nave central. Por encima sobresale levemente la cubierta con tracerâ”œÂ¡a neogâ”œâ”‚tica. A la izquierda, ventanales recayentes hacia la calle de Pedro Joaquâ”œÂ¡n Soler, y a la derecha, hacia el fondo de saco de la calle de Zaporta.', 1944, 1944, 1944, 'Anos 40', 'CENTRO', 41.65228800, -0.87712500, '0101000020E6100000C520B0726811ECBF60C9552C7ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50036946297.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50036946297.webp', 'https://www.flickr.com/photos/zaragozaantigua/50036946297/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22094, 'Calle San Vicente de Paâ”œâ•‘l 1953', 'Fotografâ”œÂ¡a de la calle de San Vicente de Paâ”œâ•‘l de Zaragoza, tomada desde el Coso Medio en junio de 1953. Aunque el proyecto de arrasar esa zona de la ciudad, desde el Coso Medio a la altura de la calle de la Yedra hasta el paseo del Ebro data de 1869, con nuevos intentos en 1887 y 1905, las obras de demoliciâ”œâ”‚n de edificios comenzaron en 1936. La "Prolongaciâ”œâ”‚n y ensanche de la calle de la Yedra" incluyâ”œâ”‚ tambiâ”œÂ®n la "Reforma de la barriada del Sepulcro", desapareciendo las calles del Câ”œÂ»ngulo, Conde de Alperche, Chantre, Graneros, Laberinto, Lezâ”œÃ­un, Red, Olivo y las plazuelas de la Leâ”œâ–’a, de la Cebada, del Reino y la de Tejedores. Se salvâ”œâ”‚ en parte la de la Rosa, y se cortaron las de Santo Dominguito de Val, San Jorge, San Lorenzo, Mayor, Don Juan de Aragâ”œâ”‚n, Palafox y Sepulcro. Entre los derribos, casas significativas, como el Palacio de Sora o Salabert. Aunque la destrucciâ”œâ”‚n mâ”œÃ­s significativa se dio en la dâ”œÂ®cada de los 40, se terminâ”œâ”‚ en 15 aâ”œâ–’os, en junio de 1951. Mide 550 metros de largo y 15 de ancho. Fuente: â”¬Ã­Aquâ”œÂ¡... Zaragoza!, Josâ”œÂ® Blasco Ijazo, 1953.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.65100600, -0.87709300, '0101000020E6100000ED9DD1562511ECBFF9BF232A54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19862801055.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19862801055.webp', 'https://www.flickr.com/photos/zaragozaantigua/19862801055/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22500, 'Colegio de los Maristas 1964', 'Dominguera y decembrina imagen capturada en el patio del colegio de los Maristas durante el encuentro de balonmano de la Divisiâ”œâ”‚n de Honor disputado entre el Ademar (Asociaciâ”œâ”‚n de exalumnos Maristas) de Zaragoza y el Atlâ”œÂ®tico de Madrid, que terminâ”œâ”‚ con el tanteador 16-14 favorable a los locales. La pequeâ”œâ–’a y abarrotada grada del fondo estaba encajada entre la irregular y dura pista de juego y la trasera de la fachada del cuerpo principal del colegio, recayente al fondo a la calle de San Vicente de Paâ”œâ•‘l. A la derecha, pequeâ”œâ–’o edificio colegial lindante con la calle de San Jorge.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65237600, -0.87629900, '0101000020E6100000658F5033A40AECBFFF58880E81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49888190777.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49888190777.webp', 'https://www.flickr.com/photos/zaragozaantigua/49888190777/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22758, 'Pl. San Pedro Nolasco 1973', 'Imagen de la plaza de San Pedro Nolasco centrada en el monumento "Zaragoza a los Hermanos Argensola", obra de Josâ”œÂ® Bueno en 1923, que en 1951 volviâ”œâ”‚ a esculpir la misma estatua femenina del centro, por su desgaste. Este monumento estaba ubicado en el centro de la plaza, antigua de San Lorenzo. En 1991, una remodelaciâ”œâ”‚n integral de la plaza desplazâ”œâ”‚ el monumento hasta su lateral disposiciâ”œâ”‚n actual (a la izquierda), y la figura femenina fue sustituida por otra nueva, completamente diferente de la original en forma y fondo, entre otros modernos cambios. Al fondo, la calle de Argensola, en direcciâ”œâ”‚n a la calle Mayor. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65278700, -0.87698400, '0101000020E61000003EB0E3BF4010ECBF812040868ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32813391002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32813391002.webp', 'https://www.flickr.com/photos/zaragozaantigua/32813391002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22943, 'Coso Bajo 1983', 'Foto: Juan Gonzâ”œÃ­lez Misis. El 4 de mayo de 1983, dos jâ”œâ”‚venes zaragozanos de 23 aâ”œâ–’os iniciaron una huelga de hambre reivindicando puestos de trabajo. En la imagen, rodeados de mensajes alusivos, en su ubicaciâ”œâ”‚n reivindicativa: el acceso al local desocupado del Coso Bajo 118, en el Edificio Espartero, esquinero con la calle de La Cadena (izquierda, fuera de plano). Fuente: Heraldo de Aragâ”œâ”‚n.', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.65077000, -0.87594700, '0101000020E610000020F0C000C207ECBFE59B6D6E4CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33453478406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33453478406.webp', 'https://www.flickr.com/photos/zaragozaantigua/33453478406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23116, 'Calle San Lorenzo 2006', 'Foto: Juan Carlos Arcos. Entrada del mercadillo San Lorenzo, en el nâ”œâ•‘mero 2 de la calle homâ”œâ”‚nima, abierta a la plaza de San Pedro Nolasco. Este establecimiento estaba dando sus â”œâ•‘ltimas bocanadas de vida, que acabâ”œâ”‚ con una prâ”œâ”‚rroga en 2009 y 2010 como "Mercado provisional San Vicente de Paâ”œâ•‘l", mientras se reformaba ese otro cercano mercado. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.65279000, -0.87664400, '0101000020E61000000A82C7B7770DECBFF3936A9F8ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31022016544.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31022016544.webp', 'https://www.flickr.com/photos/zaragozaantigua/31022016544/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23159, 'Las Piedras del Coso 2007', 'Foto: Josâ”œÂ® Miguel Marco. Vista del derribo en octubre de 2007 del edificio del Coso 101, en la esquina frente a la plaza de San Miguel (al fondo). Este lugar, denominado histâ”œâ”‚ricamente Las Piedras del Coso, alberga restos de la muralla romana, usada como cantera de sillares. Fuente: Heraldo de Aragâ”œâ”‚n.', 2007, 2007, 2007, 'Siglo XXI', 'CENTRO', 41.65081000, -0.87641900, '0101000020E61000000DFAD2DB9F0BECBF73F4F8BD4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32481641266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32481641266.webp', 'https://www.flickr.com/photos/zaragozaantigua/32481641266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23435, 'Casa de San Carlos 1877', 'Archivo RUIZ VERNACCI, Jean Laurent y Câ”œÂ¡a. 1874-1877. "Casa de la Plaza de San Carlos", o Casa de los Morlanes (1555).', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65167100, -0.87560700, '0101000020E6100000ECC1A4F8F804ECBF356090F469D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14679833938.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14679833938.webp', 'https://www.flickr.com/photos/zaragozaantigua/14679833938/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
