INSERT INTO public.photos VALUES (23456, 'Casa de los Morlanes 1918', 'Imagen de detalle de uno de los vanos de la planta noble de la antigua Casa de los Morlanes, del pleno s. XVI. Se trata de la segunda ventana desde la izquierda de la fachada principal. La Casa ejerce de vivienda â”œâ•‘til, y dos de las residentes posan en blanco nuclear, enmarcadas por laterales estâ”œÂ¡pites y rematadas con semicircular frontâ”œâ”‚n donde grutescos, angelotes y mâ”œÃ­scaras acompaâ”œâ–’an escena del Juicio de Salomâ”œâ”‚n. La Casa de los Morlanes es una casa palaciega que responde a la tipologâ”œÂ¡a del palacio aragonâ”œÂ®s renacentista, de la que se conserva la fachada en ladrillo y ornamentada. La imagen se ha capturado desde ventana del Real seminario de San Carlos Borromeo. Fuente: Instituto Amatller de Arte Hispâ”œÃ­nico (Arxiu Mas).', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.65157500, -0.87579400, '0101000020E6100000880E81238106ECBF13F241CF66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15718458087.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15718458087.webp', 'https://www.flickr.com/photos/zaragozaantigua/15718458087/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23459, 'Jean Laurent y Câ”œÂ¡a c.1877', 'Imagen parcial de un probable autorretrato de la fotogrâ”œÃ­fica sociedad francesa Jean Laurent y Câ”œÂ¡a. en la puerta de acceso a la denominada "Casa de la plaza de San Carlos" (palacio de los Morlanes) que, en el momento de esta captura visual, era sede de la "Fâ”œÃ­brica de pianos de Arilla, Menchaca y Compaâ”œâ–’â”œÂ¡a". Esta sociedad es responsable de buena parte de las mâ”œÃ­s importantes imâ”œÃ­genes de la Zaragoza de las dâ”œÂ®cadas de 1860-70. Es posible que su pertenencia al gâ”œÂ®nero "guirigabacho" siga haciendo difâ”œÂ¡cil su ingreso en el altamente selecto nomenclâ”œÃ­tor zaragozano. Salamanca ha encontrado un hueco para â”œÂ®l, no obstante las cosas. En la imagen, un feroz contraluz deja en penumbra a uno de los componentes de la "Câ”œÂ¡a" de este redomado capturainstantes, que no lo hacâ”œÂ¡a por filantropâ”œÂ¡a: se ganaba la vida con ello, era un currante de lo visual. Por ello introduce intencionadamente en el campo fotogrâ”œÃ­fico su imprescindible complemento: el carro de los abundantes materiales, productos y utensilios para el desempeâ”œâ–’o de su profesiâ”œâ”‚n. Y en el carro, la rotulaciâ”œâ”‚n comercial que le presenta y promociona: "Fotografâ”œÂ¡a de J. Laurent y Cia. Madrid, Carrera de San Gerâ”œâ”‚nimo, 39. Paris, Rue Richelieu, 90".', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65157500, -0.87579400, '0101000020E6100000880E81238106ECBF13F241CF66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17641127963.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17641127963.webp', 'https://www.flickr.com/photos/zaragozaantigua/17641127963/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23462, 'Palacio de los Morlanes c.1927', 'Imagen, desde cierta altura del Real Seminario de San Carlos Borromeo, de la plaza de San Carlos, el antiguo palacio de los Morlanes y, al fondo, tras las calle de San Jorge, el antiguo colegio de "La Enseâ”œâ–’anza" de la Compaâ”œâ–’â”œÂ¡a de Marâ”œÂ¡a, y la calle de la Zarza. Poco tiempo despuâ”œÂ®s, el colegio cerrarâ”œÂ¡a por traslado a nuevas dependencias en la calle Bilbao, y el entorno serâ”œÂ¡a radicalmente reformado: retranqueo de la calle de San Jorge, apertura de una calle paralela y particular denominada "Vicente de la Forga", apertura de una extensiâ”œâ”‚n de la calle la Yedra, y construcciâ”œâ”‚n de nuevas viviendas sobre el solar resultante de toda la manzana que antes ocupaba el colegio, su iglesia gemela de la de la Santa Cruz, y las casas del colegio. Fuente visual: Juan Mora Insa, DARA-AHPZ.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.65157500, -0.87579400, '0101000020E6100000880E81238106ECBF13F241CF66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21817962603.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21817962603.webp', 'https://www.flickr.com/photos/zaragozaantigua/21817962603/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23463, 'Palacio Morlanes 1972', 'Plaza de San Carlos: antiguo palacio de los Morlanes. Al fondo, la calle de San Jorge. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65159700, -0.87575200, '0101000020E6100000CD02ED0E2906ECBFFB95CE8767D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22775963559.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22775963559.webp', 'https://www.flickr.com/photos/zaragozaantigua/22775963559/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22114, '&quot;Casa Grande&quot; 1951', 'Imagen de la Residencia Sanitaria "Josâ”œÂ® Antonio" en su proceso de construcciâ”œâ”‚n. Diseâ”œâ–’ada por Fernando Garcâ”œÂ¡a Mercadal, las obras de este contemporâ”œÃ­neo zigurat sociosanitario comenzaron en 1948, siendo terminadas en 1952. La imagen ha sido capturada desde un tranquilo y apacible paseo de Isabel la Catâ”œâ”‚lica, sin tener que molestar demasiado a los vehâ”œÂ¡culos a motor rodantes, a la altura de los muretes del babilâ”œâ”‚nico en extensiâ”œâ”‚n "Colegio-Residencia Nuestra Seâ”œâ–’ora del Pilar para Huâ”œÂ®rfanos e Hijos del Magisterio". Fuente visual: Archivo fotogrâ”œÃ­fico ARRIBAS adquirido por el Archivo Pâ”œâ•‘blico Municipal.', 1951, 1951, 1951, 'Anos 50', 'UNIVERSIDAD', 41.63494800, -0.90007300, '0101000020E6100000496760E465CDECBF8F54DFF945D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22308592750.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22308592750.webp', 'https://www.flickr.com/photos/zaragozaantigua/22308592750/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23466, 'Casa de los Morlanes c.1970', 'La Casa de los Morlanes, de mediados del siglo XVI, fue asâ”œÂ¡ denominada porque su fachada fue posiblemente labrada por el escultor Gil Morlanes El Joven, e incluso porque allâ”œÂ¡ habrâ”œÂ¡a residido esta familia. En el â”œâ•‘ltimo tercio del siglo XIX fue sede de la Fâ”œÃ­brica de pianos de Arilla, Menchaca y Compaâ”œâ–’â”œÂ¡a, y mâ”œÃ­s recientemente el edificio pasâ”œâ”‚ a propiedad municipal, que lo rehabilitâ”œâ”‚ y dedicâ”œâ”‚ luego a diversos servicios sociales y culturales, incluyendo la Filmoteca de Zaragoza, y desde 1997 un nuevo espacio expositivo en el sâ”œâ”‚tano. La plaza de primer tâ”œÂ®rmino, antigua de la Sinagoga, fue luego plaza del Seminario y actual de San Carlos, por la inmediata presencia del Real Seminario de San Carlos Borromeo, a la derecha y en penumbra. Al fondo, la calle de San Jorge, en cuya esquina con de la Zarza estuviera hasta los aâ”œâ–’os veinte el gran colegio de la Enseâ”œâ–’anza.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65165400, -0.87573100, '0101000020E6100000F0FCA204FD05ECBF5F27F56569D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23150983865.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23150983865.webp', 'https://www.flickr.com/photos/zaragozaantigua/23150983865/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
